head.script:
/**
 * 화 면 명 : 내부매입확정
 * 메뉴경로 : 회계/관리회계/실적관리/내부거래관리/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/co/rsltsmgnt/internaltxnmgnt/co_401_03_01b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2026-01-08
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 *    5. footer에 값 처리
 * 참고사항 : 
 *    1. 그리드ID.setNoResultMessageVisible(false) 설정해줘야 그리드에 데이터없음 안보임
 *    2. 엑셀다운로드 시 Number타입 excelFormat, excelCellType 옵션 추가 작업
 *    3. "hiddenVisible":true 되어 있는 항목 일단 false 처리[hiddenCol="true" => hiddenCol="false"]
 * 테스트데이터 
 *    1. 회사코드[000], 거래일자[20100101~20101231], 매입부서[00009], 진행상태[전채]
 * 수정이력 :
 *    - 2026-01-08      배기원    최초작성
 */
//hidden 값
scwin.tempUseYn = "";    //asis 사용안함
scwin.wrkNo     = "";    //작업구분코드
scwin.fromDate  = "";    //년월
scwin.isClose   = "";    //마감체크(tobe 추가)
scwin.today     = "";    //오늘날짜

scwin.memJson;
scwin.vLoginCoCd;       //소속자회사
scwin.vLoginCoClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd;   //사용자소속구분코드
scwin.isSubCompany;
scwin.privAdmin;
scwin.acctDeptCd;
scwin.acctDeptNm;

scwin.strBasSdId = "/ui/ac/co/rsltsmgnt/internaltxnmgnt/co_401_02_02p.xml";  //상세주소
scwin.initJson = {};        //초기세팅값(TOBE)
scwin.first = 0;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                     //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];               //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];   //사용자소속구분코드
    scwin.acctDeptCd     = $c.gus.cfIsNull(scwin.memJson["acctDeptCd"]) ? "" : scwin.memJson["acctDeptCd"];         //사용자소속부서코드
    scwin.acctDeptNm     = $c.gus.cfIsNull(scwin.memJson["acctDeptNm"]) ? "" : scwin.memJson["acctDeptNm"];         //사용자소속부서
    scwin.isSubCompany   = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];           //관리자권한

    scwin.today = $c.date.getServerDateTime();

     const codeOptions = [
           { grpCd: "ZZ001", compID: "gr_txn:sysCd" }                                  //시스템코드
          ,{ grpCd: "CO003", compID: "gr_txn:internalTxnStsCd, lc_internalTxnStsCd" }  //내부거래상태
     ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);
};

/**
 * $c.data.setCommonCode 함수의 콜백함수
 */
scwin.callBackCommonCode = function () {
    scwin.initJson = dma_search.getJSON();
    scwin.first = 0;
};


/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_txn.setNoResultMessageVisible(false);
    gr_txn.setColumnColor("internalTxnBilgNo", "#007FFF");
    ds_txn.removeAll();
    totalRows.setValue("0");
};


/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_bilg, [ed_coCd, ed_coNm]);
    dma_search.setJSON(scwin.initJson);

    ica_inqStDt.setValue(scwin.today.substring(0, 6) + "01");
    ica_inqEndDt.setValue(scwin.today);
    ed_deptCd.setValue(scwin.acctDeptCd);
    ed_deptNm.setValue(scwin.acctDeptNm);
    ed_deptBilgCd.setValue("");
    ed_deptBilgNm.setValue("");
    lc_internalTxnStsCd.setValue("");

    //ed_deptCd.value = "<%=login.getAcctDeptNm()%>";
    //부서값 있어서 주석
    // scwin.f_openPushDeptPopUp('T');
};


/**
 * 조회 데이터셋 헤더 생성
 * TOBE 사용안함
 */
scwin.f_HeaderCreate = function () {
    // var GAUCE_DATASET_HEADER = "txnStDt:STRING"
    //     + ",txnEndDt:STRING"
    //     + ",acctDeptBilgCd:STRING"
    //     + ",acctDeptCd:STRING"
    //     + ",internalTxnStsCd:STRING"
    //     + ",scClsCd:STRING"
    //     + ",aggrDeptYn:DECIMAL";
    //     + ",aggrBilgDeptYn:DECIMAL";
    // ds_search.SetDataHeader(GAUCE_DATASET_HEADER);
    // ds_search.insertRow();
};


/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function () {
    scwin.setInit();
    scwin.f_setCompanyInfo();
    scwin.f_FieldClear();
};


/**
* 조회버튼
*/
scwin.f_Retrieve = async function() {
    let ret;
    ret = await $c.gus.cfValidate([tb_bilg]);
    if (!ret) {
        return false;
    }
    if (!$c.gus.cfIsAfterDate(ica_inqStDt.getValue().trim(), ica_inqEndDt.getValue().trim())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ica_inqStDt.focus();
        return false;
    }
    dma_search.set("scClsCd", "2");

    scwin.setInit();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_txn.setNoResultMessageVisible(true);
    let rowCnt  = ds_txn.getRowCount();
    totalRows.setValue(rowCnt);
    if (rowCnt > 0) {
        gr_txn.setFocusedCell(0, 0);
    } else {
        //조회결과가 존재하지 않습니다
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); 
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg)
};


/**
 * 상세버튼 클릭
 */
scwin.btn_detail_onclick = function (e) {
    scwin.f_Detail("-1");
};


/**
 * 상세(팝업호출)
 */
scwin.f_Detail = function (row) {
    // var internalTxnBilgNo = ds_txn.getCellData(row, 'internalTxnBilgNo');
    // var sFeatures = "dialogWidth:825px; dialogHeight:570px;"
    //     + "status:No; scroll:No";

    // sURL = "scwin.strBasSdId?internalTxnBilgNo=" + internalTxnBilgNo;
    // window.showModalDialog(sURL, window, sFeatures);
    let internalTxnBilgNo = ds_txn.getCellData(row=="-1"?ds_txn.getRowPosition():row, "internalTxnBilgNo");
    let opts = {};
    let data = {};
    //팝업파라메터 
    data.internalTxnBilgNo = internalTxnBilgNo;
    opts.width     = "825";
    opts.height    = "700";
    opts.id        = "popInternalTxnBilgNo";
    opts.title     = "내부거래상세조회";
    opts.popupName = "내부거래상세조회";
    opts.scrollbars = false;
    opts.type      = "browserPopup";
    $c.win.openPopup(scwin.strBasSdId, opts, data);
};


/**
 * 매입처리 버튼
 */
scwin.f_Pchs = async function () {
    //asis 소스
    // let row = ds_txn.getRowCount();
    // let ret;
    // for (let i=0; i<row; i++) {
    //     if (ds_txn.getCellData(i, "selYn") == "1" &&
    //         ds_txn.getCellData(i, "internalTxnStsCd") != ACConstants.INTERNAL_TXN_BILG) {
    //         await $c.gus.cfAlertMsg("청구상태인 data만 매입처리할 수 있습니다.");
    //         return;
    //     }
    //     //마감여부 확인
    //     if (ds_txn.getCellData(i, "selYn") == "1") {
    //         let txnDt = ds_txn.getCellData(i, "txnDt");
    //         ret = await scwin.f_JobCloseYN($c.gus.cfIsNull(txnDt)?"":txnDt.substring(0, 6));
    //         if(!ret) {
    //             return;
    //         }
    //     }
    // }
    var row = ds_txn.getMatchedIndex("selYn", "1");
    for(let i=0; i<row.length; i++) {
        if(ds_txn.getCellData(row[i], "internalTxnStsCd") != ACConstants.INTERNAL_TXN_BILG) {
            await $c.gus.cfAlertMsg("청구상태인 data만 매입처리할 수 있습니다.");
            return;
        }
        let txnDt = ds_txn.getCellData(row[i], "txnDt");
        ret = await scwin.f_JobCloseYN($c.gus.cfIsNull(txnDt)?"":txnDt.substring(0, 6));
        if(!ret) {
            return;
        }
    }

    // if (ds_txn.IsUpdated == false) {
    // 변경된 사항이 있는지 확인.
    if (ds_txn.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg("매입처리할 data가 없습니다.");
        return;
    }

    //청구할 것인지 confirm
    if (await $c.win.confirm("매입처리하시겠습니까?")) {
	    sbm_billTxn.userData1="noError";
        $c.sbm.execute(sbm_billTxn);
    }
};

scwin.sbm_billTxn_submitdone = async function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.gus.cfAlertMsg("처리되었습니다.");
        scwin.f_Retrieve();
    }
};

scwin.sbm_billTxn_submiterror = function(e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


