scwin.udc_deptCd_onclickEvent = function (e) {
    if(ed_deptCd.hidVal != ed_deptCd.getValue()) {
        ed_deptNm.setValue("");
    }
    let close = "F";
    if(!$c.gus.cfIsNull(ed_deptCd.getValue())) {
        close = "T";
    }
    let id = e.target.id;
    if(id.indexOf("btn") > -1) {
        close = "F";
    }
    scwin.f_openPushDeptPopUp(close);
};
